class AdvertisementModel {  bool? status;  List<AdvertisementData>? data;  AdvertisementModel({this.status, this.data});  AdvertisementModel.fromJson(Map<String, dynamic> json) {    status = json['status'];    if (json['data'] != null) {      data = <AdvertisementData>[];      json['data'].forEach((v) {        data!.add(new AdvertisementData.fromJson(v));      });    }  }  Map<String, dynamic> toJson() {    final Map<String, dynamic> data = new Map<String, dynamic>();    data['status'] = this.status;    if (this.data != null) {      data['data'] = this.data!.map((v) => v.toJson()).toList();    }    return data;  }}class AdvertisementData {  int? id;  String? title;  String? link;  int? isActive;  String? imageUrl;  String? createdAt;  AdvertisementData(      {this.id,        this.title,        this.link,        this.isActive,        this.imageUrl,        this.createdAt});  AdvertisementData.fromJson(Map<String, dynamic> json) {    id = json['id'];    title = json['title'];    link = json['link'];    isActive = json['is_active'];    imageUrl = json['image_url'];    createdAt = json['created_at'];  }  Map<String, dynamic> toJson() {    final Map<String, dynamic> data = new Map<String, dynamic>();    data['id'] = this.id;    data['title'] = this.title;    data['link'] = this.link;    data['is_active'] = this.isActive;    data['image_url'] = this.imageUrl;    data['created_at'] = this.createdAt;    return data;  }}